#!/usr/bin/env node
/**
 * Generate each publishable package's README from its package.json, so the
 * npm landing page and GitHub package directory have package-local docs
 * WITHOUT eight hand-maintained files drifting from the manifests.
 *
 * npm renders a package's OWN README (it does not inherit the monorepo root),
 * and pnpm does not propagate a root README into packages — so each published
 * package needs its own. The content is derived (name + description), so the
 * single source of truth is package.json.
 *
 * Usage:
 *   node scripts/generate-package-readmes.mjs --write   # (re)write READMEs
 *   node scripts/generate-package-readmes.mjs --check    # fail if any is stale
 *
 * Run --check in CI and at the top of scripts/release.mjs so a description
 * change in package.json can never silently diverge from the README.
 */
import { readFileSync, writeFileSync, readdirSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..');
const REPO = 'https://github.com/openmoq/moq-playa';
const PKGS_DIR = join(ROOT, 'packages');

const HEADER =
  '<!-- Generated by scripts/generate-package-readmes.mjs — do not edit.\n' +
  '     Content derives from this package\'s package.json (name, description).\n' +
  '     Run `node scripts/generate-package-readmes.mjs --write` after editing it. -->\n';

function render(pkg) {
  return (
    HEADER +
    `\n# ${pkg.name}\n\n` +
    `${pkg.description}\n\n` +
    `Part of [Playa](${REPO}) — a TypeScript implementation of Media over QUIC (MoQ). ` +
    `See the [project README](${REPO}#readme) for architecture and API documentation.\n\n` +
    `## Install\n\n` +
    '```sh\n' +
    `npm install ${pkg.name}\n` +
    '```\n\n' +
    `## License\n\n` +
    `[Apache-2.0](${REPO}/blob/main/LICENSE.txt)\n`
  );
}

/** Publishable packages = have a package.json that is not private. */
function publishablePackages() {
  const out = [];
  for (const dir of readdirSync(PKGS_DIR)) {
    const pf = join(PKGS_DIR, dir, 'package.json');
    if (!existsSync(pf)) continue;
    const pkg = JSON.parse(readFileSync(pf, 'utf-8'));
    if (pkg.private) continue;
    if (!pkg.description) {
      console.error(`✗ ${pkg.name || dir}: package.json has no "description" — set one first.`);
      process.exitCode = 1;
      continue;
    }
    out.push({ dir, pkg, readmePath: join(PKGS_DIR, dir, 'README.md') });
  }
  return out;
}

const mode = process.argv.includes('--check') ? 'check'
  : process.argv.includes('--write') ? 'write' : null;
if (!mode) {
  console.error('usage: generate-package-readmes.mjs --write | --check');
  process.exit(2);
}

let stale = 0;
for (const { pkg, readmePath } of publishablePackages()) {
  const expected = render(pkg);
  const actual = existsSync(readmePath) ? readFileSync(readmePath, 'utf-8') : null;
  if (actual === expected) continue;
  if (mode === 'write') {
    writeFileSync(readmePath, expected);
    console.log(`✓ ${pkg.name}`);
  } else {
    console.error(`✗ ${pkg.name}: README.md is stale (run --write)`);
    stale++;
  }
}
if (mode === 'check' && stale > 0) {
  console.error(`\n${stale} package README(s) out of date.`);
  process.exit(1);
}
if (mode === 'check') console.log('All package READMEs up to date.');
